// // This module implements a 32-bit shift register with parallel load.
// On every falling edge of the clock signal (clk) or the falling edge of the reset signal (rst), the shift register value is updated.
// If the reset signal (rst) is low, indicating a reset condition, the register value (Q) is set to 32'hFFFFFFFF.
// If the load signal is low, the input data (data_in) is loaded into the register.
// Otherwise, the register value is shifted to the right by one bit.
module Shift_register_32(
   input                clk ,
   input                rst ,
   input                load,
   input [31:0]         data_in,

   output reg [31:0]    Q  
);
    always@(posedge clk or posedge rst)begin
        if(rst) Q <= 32'b00000000000000000000000000000000;
        else if(load) Q <= data_in;
        else Q <= Q << 1;
    end
endmodule

